"""Data models for the inventory system."""


class Product:
    def __init__(self, name, price, stock):
        self.name = name
        self.price = price
        self.stock = stock

    def total_value(self):
        return self.price * self.stock

    def restock(self, amount):
        self.stock += amount

    def __repr__(self):
        return f"Product({self.name}, ${self.price}, stock={self.stock})"


class Inventory:
    def __init__(self):
        self.products = {}

    def add_product(self, product):
        self.products[product.name] = product

    def get_product(self, name):
        return self.products.get(name)

    def total_products(self):
        return len(self.products)

    def apply_discount(self, product_name, discount_pct):
        product = self.get_product(product_name)
        if product:
            product.price = product.price * (1 - discount_pct)
            return True
        return False

    def summary(self):
        lines = []
        for name, prod in sorted(self.products.items()):
            lines.append(f"  {name}: ${prod.price:.2f} x {prod.stock} = ${prod.total_value():.2f}")
        return "\n".join(lines)

